import { useEffect } from 'react';
import { useFormContext } from 'react-hook-form';

export function useFormPersist(key: string, debounce = 500) {
  const form = useFormContext();
  // Load
  useEffect(() => {
    const stored = localStorage.getItem(key);
    if (stored) {
      try { form.reset(JSON.parse(stored)); } catch { /* corrupt */ }
    }
  }, [key, form]);
  // Save
  useEffect(() => {
    let t: ReturnType<typeof setTimeout>;
    const sub = form.watch((values) => {
      clearTimeout(t);
      t = setTimeout(() => localStorage.setItem(key, JSON.stringify(values)), debounce);
    });
    return () => { sub.unsubscribe(); clearTimeout(t); };
  }, [key, form, debounce]);
}

