function useDeleteWithUndo() {
  const queryClient = useQueryClient();
  return (id: string) => {
    // Optimistic remove
    queryClient.setQueryData(['items'], (old: Item[] = []) => old.filter(i => i.id !== id));
    let cancelled = false;
    const timer = setTimeout(async () => {
      if (cancelled) return;
      await fetch(`/api/items/${id}`, { method: 'DELETE' });
    }, 5000);
    toast(t => (
      <div>
        Item deleted.
        <button onClick={() => {
          cancelled = true;
          clearTimeout(timer);
          queryClient.invalidateQueries({ queryKey: ['items'] });  // refetch
          toast.dismiss(t.id);
        }}>Undo</button>
      </div>
    ), { duration: 5000 });
  };
}

function ConditionalWrap({ condition, wrapper, children }: {
  condition: boolean;
  wrapper: (children: React.ReactNode) => JSX.Element;
  children: React.ReactNode;
}) {
  return condition ? wrapper(children) : <>{children}</>;
}

