function OnboardingWizard() {
  const form = useForm<Onboarding>();
  const [step, setStep] = useState(0);

  const nextStep = async () => {
    const fieldsForStep = stepFields[step];
    const valid = await form.trigger(fieldsForStep);
    if (!valid) return;
    // Save current step's data to backend
    await fetch('/api/onboarding/step', {
      method: 'POST',
      body: JSON.stringify({ step, data: form.getValues() })
    });
    setStep(s => s + 1);
  };

  return (
    <FormProvider {...form}>
      <form onSubmit={form.handleSubmit(submit)}>
        {step === 0 && <Step1 />}
        {step === 1 && <Step2 />}
        {/* ... */}
        <button type="button" onClick={nextStep}>Next</button>
      </form>
    </FormProvider>
  );
}

import { useQueryClient } from '@tanstack/react-query';

function ProductLink({ id, children }: { id: string; children: React.ReactNode }) {
  const qc = useQueryClient();
  const prefetch = () => {
    qc.prefetchQuery({
      queryKey: ['product', id],
      queryFn: () => fetch(`/api/products/${id}`).then(r => r.json()),
      staleTime: 30_000
    });
  };
  return (
    <Link
      to={`/products/${id}`}
      onMouseEnter={prefetch}
      onFocus={prefetch}
    >
      {children}
    </Link>
  );
}

