import { Profiler } from 'react';

const SHOULD_PROFILE = Math.random() < 0.01;  // 1% of sessions

function logRender(id: string, phase: 'mount' | 'update', actualDuration: number) {
  if (actualDuration > 16) {
    telemetry.warn('slow_render', { id, phase, duration: actualDuration });
  }
}

export function MaybeProfiler({ id, children }: { id: string; children: React.ReactNode }) {
  if (!SHOULD_PROFILE) return <>{children}</>;
  return <Profiler id={id} onRender={logRender}>{children}</Profiler>;
}

